```
try {
    m_lazy_what = detail::error_string(m_type.ptr(), m_value.ptr(), m_trace.ptr());
} catch (...) {
    std::cerr << "FATAL failure building pybind11::error_already_set error_string (" << __FILE__ << ":" << __LINE__ << ")" << std::endl;
